// n8n Function node — normalizador BR (E.164-like: 55 + DDD + número)

function pickRoot(json) {
  // Suporta payload vindo como array [{...}] ou objeto simples {...}
  if (Array.isArray(json) && json.length > 0) return json[0];
  return json;
}

function digitsOnly(str) {
  return String(str || '').replace(/\D/g, '');
}

function normalizeFromJid(jidOrNumber) {
  // 1) Tira sufixo @... se for JID e mantém só dígitos
  let raw = String(jidOrNumber || '').split('@')[0];
  let d = digitsOnly(raw);

  // 2) Garante country code 55 (remove zeros à esquerda do restante)
  if (!d.startsWith('55')) {
    d = '55' + d.replace(/^0+/, '');
  }

  // 3) Particiona: 55 + DDD(2) + local(8 ou 9)
  const cc = d.slice(0, 2);   // 55
  const ddd = d.slice(2, 4);  // ex: 51
  const local = d.slice(4);   // ex: 82892465 ou 982892465

  let with9 = null;
  let without9 = null;

  if (local.length === 8) {
    // Celular digitado sem 9
    without9 = cc + ddd + local;
    with9    = cc + ddd + '9' + local;   // canônico
  } else if (local.length === 9) {
    if (local.startsWith('9')) {
      with9    = cc + ddd + local;       // já canônico
      without9 = cc + ddd + local.slice(1);
    } else {
      // Caso atípico (fixo 9 dígitos) — não inventar 9
      with9 = without9 = cc + ddd + local;
    }
  } else {
    // Comprimento inesperado — devolve como veio
    with9 = without9 = d;
  }

  const variants = Array.from(new Set([with9, without9].filter(Boolean)));
  const canonical = with9 || d; // Preferimos COM 9 quando existir

  return {
    input_raw: String(jidOrNumber || ''),
    cc,
    ddd,
    local,
    canonical,           // ex: 5551982892465
    canonical_e164: '+' + canonical,
    variants,            // ex: ["5551982892465","555182892465"]
  };
}

// -------- Execução --------
const root = pickRoot($json);

const telCliente = root?.meta?.telefoneCliente;
const telEmpresa = root?.meta?.telefoneEmpresa;

const cliente = normalizeFromJid(telCliente);
const empresa = normalizeFromJid(telEmpresa);

return [{
  // Cliente
  phone_cliente_canonical: cliente.canonical,
  phone_cliente_canonical_e164: cliente.canonical_e164,
  phone_cliente_variants: cliente.variants,
  phone_cliente_cc: cliente.cc,
  phone_cliente_ddd: cliente.ddd,
  phone_cliente_local: cliente.local,

  // Empresa (se precisar)
  phone_empresa_canonical: empresa.canonical,
  phone_empresa_canonical_e164: empresa.canonical_e164,
  phone_empresa_variants: empresa.variants,

  // Eco útil
  nome_cliente: root?.meta?.nomeCliente,
  mensagem: root?.content?.mensagem,
  tipo_mensagem: root?.content?.tipoMensagem,
  id_mensagem: root?.content?.idMensagem,
}];

// n8n Function node — normalizador BR (E.164-like) + mapeamento do novo payload
function pickRoot(json) {
  // Suporta payload vindo como array [{...}] ou objeto simples {...}
  if (Array.isArray(json) && json.length > 0) return json[0];
  return json || {};
}

function digitsOnly(str) {
  return String(str || '').replace(/\D/g, '');
}

function normalizeFromJid(jidOrNumber) {
  if (!jidOrNumber) {
    return {
      input_raw: '',
      cc: null, ddd: null, local: null,
      canonical: null, canonical_e164: null, variants: []
    };
  }

  // 1) Tira sufixo @... se for JID e mantém só dígitos
  let raw = String(jidOrNumber || '').split('@')[0];
  let d = digitsOnly(raw);

  // 2) Garante country code 55 (remove zeros à esquerda do restante)
  if (!d.startsWith('55')) {
    d = '55' + d.replace(/^0+/, '');
  }

  // Dados mínimos: 55 + DDD(2) + local(8 ou 9) => pelo menos 12 dígitos
  if (d.length < 12) {
    return {
      input_raw: String(jidOrNumber || ''),
      cc: '55',
      ddd: null,
      local: null,
      canonical: d || null,
      canonical_e164: d ? '+' + d : null,
      variants: d ? [d] : []
    };
  }

  // 3) Particiona: 55 + DDD(2) + local
  const cc = d.slice(0, 2);   // 55
  const ddd = d.slice(2, 4);  // ex: 54
  const local = d.slice(4);   // ex: 999337424 ou 99337424

  let with9 = null;
  let without9 = null;

  if (local.length === 8) {
    // Celular digitado sem 9
    without9 = cc + ddd + local;
    with9    = cc + ddd + '9' + local;   // canônico
  } else if (local.length === 9) {
    if (local.startsWith('9')) {
      with9    = cc + ddd + local;       // já canônico
      without9 = cc + ddd + local.slice(1);
    } else {
      // Caso atípico (fixo 9 dígitos) — não inventar 9
      with9 = without9 = cc + ddd + local;
    }
  } else {
    // Comprimento inesperado — devolve como veio
    with9 = without9 = d;
  }

  const variants = Array.from(new Set([with9, without9].filter(Boolean)));
  const canonical = with9 || d; // Preferimos COM 9 quando existir

  return {
    input_raw: String(jidOrNumber || ''),
    cc,
    ddd,
    local,
    canonical,                 // ex: 5554999337424
    canonical_e164: '+' + canonical,
    variants,                  // ex: ["5554999337424","555499933742"]
  };
}

function parseHorarios(strOrArr) {
  if (Array.isArray(strOrArr)) return strOrArr;
  if (typeof strOrArr === 'string' && strOrArr.trim()) {
    try {
      const parsed = JSON.parse(strOrArr);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      return [];
    }
  }
  return [];
}

// -------- Execução --------
// 1) Pega itens do nó getClient1 (se existir). Caso contrário, usa os itens que chegaram neste Function.
const fromGetClient = $items('getClient1', 0, 0); // pode retornar [] se o nó não existir nesse branch
const sourceItems = (fromGetClient && fromGetClient.length > 0)
  ? fromGetClient.map(i => i.json)
  : items.map(i => i.json); // fallback para os itens atuais

// 2) Processa TODOS os itens e retorna 1 saída por usuário
const out = sourceItems.map((src) => {
  const root = pickRoot(src);

  // Telefone agora vem em root.telefone (ex: "5554999337424@s.whatsapp.net")
  const telJid = root?.telefone;
  const pessoa = normalizeFromJid(telJid);

  // Parse seguro dos horários de refeições
  const horariosArray = parseHorarios(root?.horarios_refeicoes);

  return {
    json: {
      // Normalização do telefone
      telefone_jid: telJid || null,
      phone_canonical: pessoa.canonical,
      phone_canonical_e164: pessoa.canonical_e164,
      phone_variants: pessoa.variants,
      phone_cc: pessoa.cc,
      phone_ddd: pessoa.ddd,
      phone_local: pessoa.local,

      // Campos do payload original (eco para downstream)
      id: root?.id ?? null,
      nome: root?.nome ?? null,
      sexo: root?.sexo ?? null,
      altura_cm: root?.altura_cm ?? null,
      peso_atual_kg: root?.peso_atual_kg ?? null,
      nivel_atividade: root?.nivel_atividade ?? null,
      objetivo: root?.objetivo ?? null,
      restricoes: Array.isArray(root?.restricoes) ? root.restricoes : [],
      modo_macros: root?.modo_macros ?? null,
      data_criacao: root?.data_criacao ?? null,
      tem_macros: !!root?.tem_macros,
      idade: root?.idade ?? null,
      refeicoes: root?.refeicoes ?? null,
      horarios_refeicoes: horariosArray,                 // sempre array
      horarios_refeicoes_raw: root?.horarios_refeicoes ?? null, // original
      idmensagem: root?.idmensagem ?? null,
      session_id: root?.session_id ?? null,
    }
  };
});

return out;

// 🧮 Função para calcular macronutrientes
// Entradas esperadas em $json: 
// sexo, altura_cm, peso_atual_kg, nivel_atividade, objetivo, idade

const sexo = String($json.sexo).toLowerCase();
const altura = Number($json.altura_cm);
const peso = Number($json.peso_atual_kg);
const idade = Number($json.idade);
const nivel = String($json.nivel_atividade).toLowerCase();
const objetivo = String($json.objetivo).toLowerCase();

// 1️⃣ Fatores de atividade
const fatores = {
  sedentario: 1.2,
  leve: 1.375,
  moderado: 1.55,
  intenso: 1.725,
  muito_intenso: 1.9
};

// 2️⃣ TMB (Mifflin-St Jeor)
let TMB = 10 * peso + 6.25 * altura - 5 * idade + (sexo === 'masculino' ? 5 : -161);

// 3️⃣ GET
const fatorAtividade = fatores[nivel] || 1.2;
const GET = TMB * fatorAtividade;

// 4️⃣ Calorias alvo
let calorias;
if (objetivo === 'emagrecer') calorias = GET - 500;
else if (objetivo === 'ganhar') calorias = GET + 500;
else calorias = GET;

// 5️⃣ Proteínas (g)
let proteina = 0;
if (objetivo === 'emagrecer') proteina = 2.0 * peso;
else if (objetivo === 'manter') proteina = 1.6 * peso;
else if (objetivo === 'ganhar') proteina = 2.2 * peso;

// 6️⃣ Gorduras (g)
let gordura = (calorias * 0.25) / 9;

// 7️⃣ Carboidratos (g)
let carbo = (calorias - (proteina * 4 + gordura * 9)) / 4;

// 🔢 Arredondamento (padrão aritmético)
proteina = Math.round(proteina);
gordura = Math.round(gordura);
carbo = Math.round(carbo);
calorias = Math.round(calorias);

// 8️⃣ Ajuste de consistência (carboidrato)
const totalCheck = proteina * 4 + carbo * 4 + gordura * 9;
if (Math.abs(totalCheck - calorias) > 5) {
  carbo = Math.round((calorias - (proteina * 4 + gordura * 9)) / 4);
}

return [
  {
    json: {
      proteina_g: proteina,
      carboidratos_g: carbo,
      gorduras_g: gordura,
      calorias: calorias
    }
  }
];

const msg = $json.body?.message;
if (!msg) return [];
if (msg.wasSentByApi) return [];
if (msg.fromMe) return [];
return items;

